    def test_live_work_progress_flushes_stdout_before_stderr(self):
        from mew.commands import work_ai_progress

        class FlushSpy(StringIO):
            def __init__(self):
                super().__init__()
                self.flush_count = 0

            def flush(self):
                self.flush_count += 1
                super().flush()

        stdout = FlushSpy()
        stderr = StringIO()
        args = SimpleNamespace(live=True, progress=False, json=False)

        with redirect_stdout(stdout), redirect_stderr(stderr):
            work_ai_progress(args)("THINK ok")

        self.assertEqual(stdout.flush_count, 1)
        self.assertIn("mew work ai: THINK ok", stderr.getvalue())

    def test_work_live_refuses_when_any_work_session_is_already_running(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                with state_lock():
                    state = load_state()
                    task = add_coding_task(state)
                    session, _ = create_work_session(state, task)
                    session["model_turns"].append({"id": 1, "status": "running"})
                    save_state(state)

                with redirect_stdout(StringIO()) as stdout, redirect_stderr(StringIO()):
                    code = main(["work", "1", "--live", "--allow-read", ".", "--max-steps", "1"])

                self.assertEqual(code, 1)
                self.assertIn("work_already_running", stdout.getvalue())
                self.assertIn("session=#1 task=#1", stdout.getvalue())
            finally:
                os.chdir(old_cwd)

