    def test_work_session_resume_builds_verifier_failure_repair_agenda(self):
        from mew.work_session import build_work_session_resume, format_work_session_resume

        stderr = "\n".join(
            [
                "Traceback (most recent call last):",
                '  File "/usr/local/lib/python3.13/site-packages/pkg/invariants.py", line 137, in run',
                "    dtype = n.complex if isinstance(variable, n.complex) else n.float",
                "AttributeError: module 'numpy' has no attribute 'complex'.",
                "AttributeError: module 'numpy' has no attribute 'float'.",
                "ImportError: cannot import name 'gcd' from 'fractions'",
                "tests/test_widget.py:42: AssertionError: legacy alias still broken",
            ]
        )
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Repair verifier failure",
            "goal": "Use verifier output to drive the next edit.",
            "updated_at": "now",
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "run_command",
                    "status": "completed",
                    "parameters": {"command": "python -m pytest"},
                    "result": {"command": "python -m pytest", "cwd": "/app", "exit_code": 1, "stderr": stderr},
                    "error": "run_command failed with exit_code=1",
                },
                {
                    "id": 2,
                    "tool": "edit_file",
                    "status": "completed",
                    "parameters": {"path": "pkg/invariants.py"},
                    "result": {
                        "path": "pkg/invariants.py",
                        "changed": True,
                        "dry_run": True,
                        "written": False,
                    },
                },
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session)
        agenda = resume["verifier_failure_repair_agenda"]
        self.assertEqual(agenda["source_tool_call_id"], 1)
        self.assertEqual(agenda["exit_code"], 1)
        self.assertIn("complex", agenda["symbols"])
        self.assertIn("float", agenda["symbols"])
        self.assertIn("gcd", agenda["symbols"])
        self.assertEqual(
            agenda["sibling_search_queries"],
            [
                "numpy.complex",
                "np.complex",
                "numpy.float",
                "np.float",
                "from fractions import gcd",
                "fractions.gcd",
            ],
        )
        self.assertEqual(
            agenda["source_locations"][0],
            {"path": "/usr/local/lib/python3.13/site-packages/pkg/invariants.py", "line": "137"},
        )
        self.assertIn({"path": "tests/test_widget.py", "line": "42"}, agenda["source_locations"])
        self.assertEqual(agenda["latest_changed_dry_run_write"]["tool_call_id"], 2)
        self.assertIn("small applied edit batch", agenda["suggested_next"])

        text = format_work_session_resume(resume)
        self.assertIn("verifier_failure_repair_agenda: tool=#1 exit=1 run_command", text)
        self.assertIn("verifier_failure_symbols: complex, float, gcd", text)
        self.assertIn(
            "verifier_failure_sibling_searches: "
            "numpy.complex, np.complex, numpy.float, np.float, from fractions import gcd, fractions.gcd",
            text,
        )
        self.assertIn("/usr/local/lib/python3.13/site-packages/pkg/invariants.py:137", text)
        self.assertIn("verifier_failure_latest_dry_run: #2 pkg/invariants.py", text)

    def test_work_session_resume_builds_runtime_contract_gap_for_vm_failure(self):
        from mew.work_session import build_work_session_resume, format_work_session_resume

        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Build source artifact for custom VM",
            "goal": "Build the provided source into an ELF and run it with vm.js.",
            "updated_at": "now",
            "tool_calls": [
                {
                    "id": 7,
                    "tool": "run_command",
                    "status": "completed",
                    "parameters": {"command": "node vm.js", "cwd": "/app"},
                    "result": {
                        "command": "node vm.js",
                        "cwd": "/app",
                        "exit_code": 1,
                        "stdout": "frame artifact:\nmissing /tmp/frame.bmp\n",
                        "stderr": "Execution error at PC=0x47be38: Unknown SPECIAL3 function: 0x3b\n",
                    },
                    "error": "run_command failed with exit_code=1",
                },
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session)
        agenda = resume["verifier_failure_repair_agenda"]
        runtime_gap = agenda["runtime_contract_gap"]

        self.assertEqual(runtime_gap["kind"], "unsupported_opcode_instruction_set")
        self.assertEqual(runtime_gap["signature"]["pc"], "0x47be38")
        self.assertEqual(runtime_gap["signature"]["special_function"], "0x3b")
        self.assertEqual(runtime_gap["signature"]["expected_artifacts"], ["/tmp/frame.bmp"])
        self.assertEqual(runtime_gap["recommended_tools"], ["readelf", "nm", "objdump", "addr2line"])
        self.assertIn("map the failed runtime signature", agenda["suggested_next"])

        text = format_work_session_resume(resume)
        self.assertIn("verifier_failure_runtime_gap: unsupported_opcode_instruction_set", text)
        self.assertIn("pc=0x47be38", text)
        self.assertIn("special_function=0x3b", text)
        self.assertIn("expected_artifacts=/tmp/frame.bmp", text)
        self.assertIn("verifier_failure_runtime_tools: readelf, nm, objdump, addr2line", text)

    def test_work_session_resume_surfaces_long_build_state(self):
        from mew.work_session import build_work_session_resume, format_work_session_resume

        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Compile CompCert",
            "goal": (
                "Under /tmp/CompCert/, build the CompCert C verified compiler from source. "
                "Ensure that CompCert can be invoked through /tmp/CompCert/ccomp."
            ),
            "updated_at": "now",
            "tool_calls": [
                {
                    "id": 3,
                    "tool": "run_command",
                    "status": "completed",
                    "parameters": {"command": "opam install -y coq.8.16.1 coq-flocq"},
                    "result": {"command": "opam install -y coq.8.16.1 coq-flocq", "exit_code": 0},
                },
                {
                    "id": 9,
                    "tool": "run_command",
                    "status": "completed",
                    "parameters": {"command": "make depend && timeout 120 make -j4 ccomp", "cwd": "/tmp/CompCert"},
                    "result": {
                        "command": "make depend && timeout 120 make -j4 ccomp",
                        "cwd": "/tmp/CompCert",
                        "exit_code": 0,
                        "stdout": (
                            "SOURCE_ARCHIVE_ROOT=CompCert-3.13.1\n"
                            "opam switch compcert-ocaml-system\n"
                            "make depend\n.depend generated\n"
                            "Error: Can't find file ./Axioms.v\n"
                            "MAKE_FAILED_OR_TIMEOUT exit=124\n"
                        ),
                    },
                },
                {
                    "id": 10,
                    "tool": "run_command",
                    "status": "running",
                    "parameters": {"command": "make depend && make -j2 ccomp", "cwd": "/tmp/CompCert"},
                    "result": {
                        "command": "make depend && make -j2 ccomp",
                        "cwd": "/tmp/CompCert",
                        "exit_code": None,
                    },
                    "running_output": {"stdout": "COQC backend/Asmgenproof0.v\nCOQC x86/Asmgenproof1.v\n"},
                },
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session)
