    def test_work_session_runs_read_only_tools_and_journals_results(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("hello native hands\nshared-needle in docs\n", encoding="utf-8")
                Path("src").mkdir()
                Path("src/app.py").write_text("print('shared-needle in code')\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--start-session", "--json"]), 0)
                created = json.loads(stdout.getvalue())
                self.assertTrue(created["created"])
                self.assertEqual(created["work_session"]["task_id"], 1)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "read_file",
                                "--path",
                                "README.md",
                                "--allow-read",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )
                read_result = json.loads(stdout.getvalue())
                self.assertEqual(read_result["tool_call"]["status"], "completed")
                self.assertIn("hello native hands", read_result["tool_call"]["result"]["text"])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "glob",
                                "--pattern",
                                "*.py",
                                "--path",
                                ".",
                                "--allow-read",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )
                glob_result = json.loads(stdout.getvalue())
                self.assertEqual(glob_result["tool_call"]["status"], "completed")
                self.assertTrue(
                    any(match["path"].endswith("src/app.py") for match in glob_result["tool_call"]["result"]["matches"])
                )

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "search_text",
                                "--query",
                                "shared-needle",
                                "--pattern",
                                "*.md",
                                "--path",
                                ".",
                                "--allow-read",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )
                search_result = json.loads(stdout.getvalue())
                self.assertEqual(search_result["tool_call"]["status"], "completed")
                matches = search_result["tool_call"]["result"]["matches"]
                self.assertEqual(search_result["tool_call"]["result"]["pattern"], "*.md")
                self.assertTrue(any(match.endswith("shared-needle in docs") for match in matches))
                self.assertFalse(any("src/app.py" in match for match in matches))

                state = load_state()
                session = state["work_sessions"][0]
                self.assertEqual(session["status"], "active")
                self.assertEqual([call["tool"] for call in session["tool_calls"]], ["read_file", "glob", "search_text"])
                self.assertEqual(session["tool_calls"][0]["status"], "completed")

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1"]), 0)
                text = stdout.getvalue()
                self.assertIn("Work session", text)
                self.assertIn("phase=idle", text)
                self.assertIn("tool_calls=3", text)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session"]), 0)
                session_text = stdout.getvalue()
                self.assertIn("Read file", session_text)
                self.assertIn("matches=1", session_text)
                self.assertNotIn("hello native hands", session_text)
            finally:
                os.chdir(old_cwd)

    def test_work_oneshot_creates_generic_task_session_and_report(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            state_root = Path(tmp) / "state"
            workspace = Path(tmp) / "workspace"
            state_root.mkdir()
            workspace.mkdir()
            report_path = Path(tmp) / "report.json"
            os.chdir(state_root)
            try:
                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "--oneshot",
                                "--instruction",
                                "Inspect this workspace.",
                                "--title",
                                "Generic one-shot",
                                "--cwd",
                                str(workspace),
                                "--allow-read",
                                ".",
                                "--max-steps",
                                "0",
                                "--report",
                                str(report_path),
                                "--json",
                            ]
                        ),
                        0,
                    )

                payload = json.loads(stdout.getvalue())
                self.assertEqual(payload["summary"], "mew work --oneshot completed generic work-session attempt")
                self.assertEqual(payload["workspace_cwd"], str(workspace))
                self.assertEqual(payload["work_exit_code"], 0)
                self.assertTrue(report_path.exists())
                saved = json.loads(report_path.read_text(encoding="utf-8"))
                self.assertEqual(saved["task_id"], payload["task_id"])

                state = load_state()
                task = state["tasks"][0]
                self.assertEqual(task["title"], "Generic one-shot")
                self.assertEqual(task["description"], "Inspect this workspace.")
                self.assertEqual(task["cwd"], str(workspace))
                self.assertEqual(state["work_sessions"][0]["task_id"], task["id"])
            finally:
                os.chdir(old_cwd)

