    def test_reject_resident_mew_loop_command_recognizes_wrappers(self):
        from mew.work_session import reject_resident_mew_loop_command

        for command in (
            "./mew work 1 --live",
            "PYTHONPATH=. ./mew work 1 --live",
            "/usr/bin/env mew work 1 --live",
            "env -- ./mew work 1 --live",
            "env -i ./mew work 1 --live",
            "env -S './mew work 1 --live'",
            "FOO=1 /usr/bin/env mew work 1 --live",
            "/usr/bin/env --split-string='python -m mew run'",
            "uv run mew work 1 --live",
            "FOO=1 uv run mew work 1 --live",
            "uv run --with foo mew work 1 --live",
            "uv run -- mew work 1 --live",
            "python -m mew run",
            "python3 -I -m mew work 1 --live",
            "A=1 python -m mew run",
        ):
            with self.assertRaisesRegex(ValueError, "resident mew loops"):
                reject_resident_mew_loop_command(command)

        reject_resident_mew_loop_command("uv run pytest -q")
        reject_resident_mew_loop_command("/usr/bin/env python -V")
        reject_resident_mew_loop_command("env -- echo mew work 1 --live")
        reject_resident_mew_loop_command("echo mew work 1 --live")
        reject_resident_mew_loop_command("python helper.py mew work 1 --live")

    def test_work_session_git_tools_are_read_only_and_gated(self):
        if not shutil.which("git"):
            self.skipTest("git not found")
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                subprocess.run(["git", "init"], check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
                Path("app.py").write_text("print('old')\n", encoding="utf-8")
                subprocess.run(["git", "add", "app.py"], check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
                subprocess.run(
                    [
                        "git",
                        "-c",
                        "user.email=mew@example.invalid",
                        "-c",
                        "user.name=mew",
                        "commit",
                        "-m",
                        "init",
                    ],
                    check=True,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    text=True,
                )
                Path("app.py").write_text("print('new')\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--tool", "git_status", "--json"]), 1)
                self.assertIn("git inspection is disabled", stdout.getvalue())

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(["work", "1", "--tool", "git_status", "--allow-read", ".", "--json"]),
                        0,
                    )
                status_data = json.loads(stdout.getvalue())
                self.assertEqual(status_data["tool_call"]["status"], "completed")
                self.assertIn(" M app.py", status_data["tool_call"]["result"]["stdout"])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(["work", "1", "--tool", "git_diff", "--allow-read", ".", "--json"]),
                        0,
                    )
                diff_data = json.loads(stdout.getvalue())
                diff_text = diff_data["tool_call"]["result"]["stdout"]
                self.assertIn("-print('old')", diff_text)
                self.assertIn("+print('new')", diff_text)
            finally:
                os.chdir(old_cwd)

