    def test_work_interrupt_submit_sets_boundary_stop_and_pending_steer(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--interrupt-submit", "switch to urgent check", "--json"]), 0)
                data = json.loads(stdout.getvalue())
                self.assertEqual(data["stop_request"]["action"], "interrupt_submit")
                self.assertEqual(data["stop_request"]["submit_text"], "switch to urgent check")
                self.assertEqual(data["pending_steer"]["source"], "interrupt_submit")

                from mew.work_session import build_work_session_resume, format_work_session_resume

                state = load_state()
                session = state["work_sessions"][0]
                self.assertEqual(session["stop_action"], "interrupt_submit")
                self.assertEqual(session["pending_steer"]["text"], "switch to urgent check")
                resume = build_work_session_resume(session, task=state["tasks"][0])
                text = format_work_session_resume(resume)
                self.assertIn("Stop request", text)
                self.assertIn("action: interrupt_submit", text)
                self.assertIn("Pending steer", text)
                self.assertIn("continue to submit pending interrupt", resume["next_action"])
                self.assertIn("mew work 1 --live", resume["next_action"])
                controls = format_work_cockpit_controls(
                    state=state,
                    session=session,
                    continue_options="--allow-read src --max-steps 1",
                )
                self.assertIn("- /c --allow-read src --max-steps 1", controls)
                self.assertIn("- /follow --allow-read src --max-steps 10", controls)

                uncached_controls = format_work_cockpit_controls(
                    state=state,
                    session=session,
                    continue_options="",
                )
                self.assertIn('- /continue --allow-read . --work-guidance "focus ..."', uncached_controls)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session"]), 0)
                controls_block = stdout.getvalue().split("Next CLI controls", 1)[1]
                self.assertIn("submit pending interrupt: mew work 1 --live", controls_block)
                self.assertNotIn("stop requested snapshot", controls_block)
            finally:
                os.chdir(old_cwd)

