    def test_work_session_recovers_interrupted_read_tool(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("recover me\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    state["work_sessions"].append(
                        {
                            "id": 1,
                            "task_id": 1,
                            "status": "active",
                            "title": "Build native hands",
                            "goal": "Recover read.",
                            "created_at": "then",
                            "updated_at": "then",
                            "last_tool_call_id": 1,
                            "last_model_turn_id": 1,
                            "tool_calls": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "tool": "read_file",
                                    "status": "running",
                                    "parameters": {"path": "README.md"},
                                    "result": None,
                                    "summary": "",
                                    "error": "",
                                    "started_at": "then",
                                    "finished_at": None,
                                }
                            ],
                            "model_turns": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "status": "running",
                                    "decision_plan": {},
                                    "action_plan": {},
                                    "action": {"type": "read_file", "path": "README.md"},
                                    "tool_call_id": 1,
                                    "summary": "",
                                    "error": "",
                                    "started_at": "then",
                                    "finished_at": None,
                                }
                            ],
                        }
                    )
                    save_state(state)

                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["repair", "--force", "--json"]), 0)
                self.assertEqual(load_state()["work_sessions"][0]["tool_calls"][0]["status"], "interrupted")

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                interrupted_resume = json.loads(stdout.getvalue())["resume"]
                self.assertEqual(interrupted_resume["phase"], "interrupted")
                self.assertEqual(interrupted_resume["recovery_plan"]["items"][0]["action"], "retry_tool")
                self.assertIn("recover-session", interrupted_resume["recovery_plan"]["items"][0]["hint"])
                self.assertIn("--allow-read README.md", interrupted_resume["recovery_plan"]["items"][0]["hint"])
                self.assertIn("--auto-recover-safe", interrupted_resume["recovery_plan"]["items"][0]["auto_hint"])
                self.assertIn("--auto-recover-safe", interrupted_resume["recovery_plan"]["items"][0]["chat_auto_hint"])
                self.assertEqual(interrupted_resume["recovery_plan"]["items"][0]["path"], "README.md")
                self.assertIn("--auto-recover-safe", stdout.getvalue())

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--allow-read", ".", "--json"]), 0)
                world_resume = json.loads(stdout.getvalue())["resume"]
                self.assertIn("world_state", world_resume)
                self.assertIn("live world check: review git status", world_resume["next_action"])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume"]), 0)
                text_resume = stdout.getvalue()
                self.assertIn("Recovery plan", text_resume)
                self.assertIn("summary: interrupted work tool call", text_resume)
                self.assertIn("error: Interrupted before the work tool completed.", text_resume)
                self.assertIn("recovery_hint: Review work session #1 resume", text_resume)
                self.assertIn("auto: mew work 1 --session --resume --allow-read README.md --auto-recover-safe", text_resume)
                self.assertIn("chat_auto: /work-session resume 1 --allow-read README.md --auto-recover-safe", text_resume)
                self.assertIn("path: README.md", text_resume)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--recover-session", "--allow-read", ".", "--json"]), 0)
                report = json.loads(stdout.getvalue())

                self.assertEqual(report["recovery"]["action"], "retry_tool")
                self.assertEqual(report["recovery"]["source_tool_call_id"], 1)
                self.assertIn("world_state_before", report["recovery"])
                self.assertEqual(report["tool_call"]["tool"], "read_file")
                self.assertIn("recover me", report["tool_call"]["result"]["text"])
                session = load_state()["work_sessions"][0]
                self.assertEqual(session["tool_calls"][0]["recovery_status"], "superseded")
                self.assertEqual(session["tool_calls"][0]["recovered_by_tool_call_id"], 2)
                self.assertEqual(session["model_turns"][0]["recovery_status"], "superseded")
                self.assertEqual(session["model_turns"][0]["recovered_by_tool_call_id"], 2)
                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                recovered_resume = json.loads(stdout.getvalue())["resume"]
                self.assertEqual(recovered_resume["phase"], "idle")
                self.assertEqual(recovered_resume["failures"][0]["recovery_status"], "superseded")
                self.assertEqual(recovered_resume["failures"][0]["recovered_by_tool_call_id"], 2)
                self.assertEqual(recovered_resume["suggested_safe_reobserve"], {})
                self.assertNotIn("suggested_safe_reobserve", recovered_resume["failures"][0])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume"]), 0)
                recovered_text = stdout.getvalue()
                self.assertIn("recovery=superseded by=#2", recovered_text)
                self.assertNotIn("reobserve:", recovered_text)
            finally:
                os.chdir(old_cwd)

    def test_work_session_recovers_interrupted_run_tests_with_verify_gate(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                command = f"{shlex.quote(sys.executable)} -c 'print(\"verify ok\")'"
                equivalent_command = f'{shlex.quote(sys.executable)} -c "print(\\"verify ok\\")"'
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    state["work_sessions"].append(
                        {
                            "id": 1,
                            "task_id": 1,
                            "status": "active",
                            "title": "Build native hands",
                            "goal": "Recover verification.",
                            "created_at": "then",
                            "updated_at": "then",
                            "last_tool_call_id": 1,
                            "last_model_turn_id": 1,
                            "tool_calls": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "tool": "run_tests",
                                    "status": "interrupted",
                                    "parameters": {"command": command, "cwd": "."},
                                    "result": None,
                                    "summary": "interrupted verifier",
                                    "error": "Interrupted before the verifier completed.",
                                    "started_at": "then",
                                    "finished_at": None,
                                }
                            ],
                            "model_turns": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "status": "interrupted",
                                    "decision_plan": {},
                                    "action_plan": {},
                                    "action": {"type": "run_tests", "command": command},
                                    "tool_call_id": 1,
                                    "summary": "interrupted verifier turn",
                                    "error": "Interrupted before the work tool completed.",
                                    "started_at": "then",
                                    "finished_at": None,
                                }
                            ],
                        }
                    )
                    save_state(state)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                interrupted_resume = json.loads(stdout.getvalue())["resume"]
                item = interrupted_resume["recovery_plan"]["items"][0]
                self.assertEqual(item["action"], "retry_verification")
                self.assertEqual(item["safety"], "verification")
                self.assertEqual(item["command"], command)
                self.assertIn("--allow-verify", item["hint"])
                self.assertIn(shlex.quote(command), item["hint"])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--recover-session", "--allow-read", ".", "--json"]), 0)
                no_gate = json.loads(stdout.getvalue())
                self.assertEqual(no_gate["recovery"]["action"], "needs_verify_gate")

                with tempfile.TemporaryDirectory() as outside_tmp:
                    with state_lock():
                        state = load_state()
                        state["work_sessions"][0]["tool_calls"][0]["parameters"]["cwd"] = outside_tmp
                        save_state(state)
                    with redirect_stdout(StringIO()) as stdout:
                        self.assertEqual(
                            main(
                                [
                                    "work",
                                    "1",
                                    "--recover-session",
                                    "--allow-read",
                                    ".",
                                    "--allow-verify",
                                    "--verify-command",
                                    command,
                                    "--json",
                                ]
                            ),
                            0,
                        )
                    outside_gate = json.loads(stdout.getvalue())
                    self.assertEqual(outside_gate["recovery"]["action"], "needs_read_gate")
                    self.assertEqual(outside_gate["recovery"]["cwd"], outside_tmp)
                    with state_lock():
                        state = load_state()
                        state["work_sessions"][0]["tool_calls"][0]["parameters"]["cwd"] = "."
                        save_state(state)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--recover-session",
                                "--allow-read",
                                ".",
                                "--allow-verify",
                                "--verify-command",
                                f"{shlex.quote(sys.executable)} -V",
                                "--json",
                            ]
                        ),
                        0,
                    )
                mismatch = json.loads(stdout.getvalue())
                self.assertEqual(mismatch["recovery"]["action"], "needs_matching_verifier")
                self.assertEqual(mismatch["recovery"]["command"], command)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--recover-session",
                                "--allow-read",
                                ".",
                                "--allow-verify",
                                "--verify-command",
                                equivalent_command,
                                "--json",
                            ]
                        ),
                        0,
                    )
                report = json.loads(stdout.getvalue())
                self.assertEqual(report["recovery"]["action"], "retry_tool")
                self.assertEqual(report["recovery"]["tool"], "run_tests")
                self.assertIn("world_state_before", report["recovery"])
                self.assertEqual(report["tool_call"]["status"], "completed")
                self.assertEqual(report["tool_call"]["result"]["exit_code"], 0)
                self.assertIn("verify ok", report["tool_call"]["result"]["stdout"])

                session = load_state()["work_sessions"][0]
                self.assertEqual(session["tool_calls"][0]["recovery_status"], "superseded")
                self.assertEqual(session["tool_calls"][0]["recovered_by_tool_call_id"], 2)
                self.assertEqual(session["model_turns"][0]["recovery_status"], "superseded")
                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                recovered_resume = json.loads(stdout.getvalue())["resume"]
                self.assertEqual(recovered_resume["phase"], "idle")
                self.assertEqual(recovered_resume["failures"][0]["recovery_status"], "superseded")
            finally:
                os.chdir(old_cwd)

