    def test_work_recovery_plan_includes_side_effect_review_context(self):
        from mew.commands import format_work_cockpit_controls
        from mew.work_session import build_work_session_resume, format_work_session_resume

        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "goal": "Recover side effects.",
            "created_at": "then",
            "updated_at": "now",
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "run_command",
                    "status": "interrupted",
                    "parameters": {"command": "python mutate.py", "cwd": "."},
                },
                {
                    "id": 2,
                    "tool": "edit_file",
                    "status": "interrupted",
                    "parameters": {"path": "README.md"},
                },
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session)
        items = resume["recovery_plan"]["items"]

        self.assertEqual(resume["commands"][0]["command"], "python mutate.py")
        self.assertEqual(resume["commands"][0]["cwd"], ".")
        self.assertEqual(items[0]["action"], "needs_user_review")
        self.assertEqual(items[0]["safety"], "command")
        self.assertEqual(items[0]["effect_classification"], "action_committed")
        self.assertEqual(items[0]["command"], "python mutate.py")
        self.assertEqual(items[0]["cwd"], ".")
        self.assertIn("--session --resume --allow-read", items[0]["review_hint"])
        self.assertIn("idempotent", " ".join(items[0]["review_steps"]))
        self.assertEqual(items[1]["action"], "retry_dry_run_write")
        self.assertEqual(items[1]["safety"], "dry_run_write")
        self.assertEqual(items[1]["effect_classification"], "no_action")
        self.assertEqual(items[1]["path"], "README.md")
        self.assertIn("--recover-session --allow-write README.md", items[1]["hint"])

        text = format_work_session_resume(resume)
        self.assertIn("effect=action_committed", text)
        self.assertIn("effect=no_action", text)
        self.assertIn("review: ./mew work 1 --session --resume --allow-read .", text)
        self.assertIn("hint: ./mew work 1 --recover-session --allow-write README.md", text)
        self.assertIn("command: python mutate.py", text)
        self.assertIn("path: README.md", text)
        controls = format_work_cockpit_controls(state={"work_sessions": [session], "tasks": []}, session=session)
        self.assertIn("Recovery\n- ./mew work 1 --session --resume --allow-read .", controls)

