    def test_work_json_accept_edits_batch_can_defer_verification_without_command(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("old text\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                model_output = {
                    "summary": "preview batch for external verifier",
                    "action": {
                        "type": "batch",
                        "tools": [
                            {
                                "type": "edit_file",
                                "path": "README.md",
                                "old": "old text",
                                "new": "new text",
                            },
                            {
                                "type": "write_file",
                                "path": "report.jsonl",
                                "content": "{}\n",
                                "create": True,
                            },
                        ],
                    },
                }
                with patch("mew.commands.load_model_auth", return_value={"path": "auth.json"}):
                    with patch("mew.work_loop.call_model_json_with_retries", return_value=model_output):
                        with redirect_stdout(StringIO()) as stdout, redirect_stderr(StringIO()):
                            self.assertEqual(
                                main(
                                    [
                                        "work",
                                        "1",
                                        "--ai",
                                        "--json",
                                        "--auth",
                                        "auth.json",
                                        "--allow-read",
                                        ".",
                                        "--allow-write",
                                        ".",
                                        "--approval-mode",
                                        "accept-edits",
                                        "--defer-verify",
                                        "--max-steps",
                                        "1",
                                        "--act-mode",
                                        "deterministic",
                                    ]
                                ),
                                0,
                            )

                report = json.loads(stdout.getvalue())
                step = report["steps"][0]
                self.assertEqual(step["inline_approval"], "auto_applied")
                self.assertEqual(step["inline_approval_count"], 2)
                self.assertEqual(Path("README.md").read_text(encoding="utf-8"), "new text\n")
                self.assertEqual(Path("report.jsonl").read_text(encoding="utf-8"), "{}\n")
                session = load_state()["work_sessions"][0]
                apply_results = [call["result"] for call in session["tool_calls"][2:4]]
                self.assertEqual(sum(1 for result in apply_results if result.get("verification_deferred")), 2)
                self.assertTrue(all("verification_exit_code" not in result for result in apply_results))
            finally:
                os.chdir(old_cwd)

    def test_work_think_prompt_guides_independent_reads_to_batch(self):
        from mew.work_loop import build_work_think_prompt

        prompt = build_work_think_prompt({"work_session": {"tool_calls": []}})
        self.assertIn("Treat guidance as the user's current instruction", prompt)
        self.assertIn("do not finish solely because older notes", prompt)
        self.assertIn("guidance_snapshot", prompt)
        self.assertIn("recent_read_file_windows", prompt)
        self.assertIn("reuse that recent window instead of issuing another same-span read_file", prompt)
        self.assertIn("fall back to the matching read_file tool_calls result text", prompt)
        self.assertIn("not current instructions", prompt)
        self.assertIn("capabilities object as current and authoritative", prompt)
        self.assertIn("Keep working_memory.open_questions limited to unanswered items", prompt)
        self.assertIn("work_session.resume.active_memory", prompt)
        self.assertIn("durable typed recall", prompt)
        self.assertIn("Do not use read_file on .mew/memory/private paths", prompt)
        self.assertIn("Use work_session.current_run as the active invocation budget", prompt)
        self.assertIn("work_session.effort as historical session pressure", prompt)
        self.assertIn("Do not claim the step or failure budget is exhausted", prompt)
        self.assertIn("current_run still has remaining steps", prompt)
        self.assertIn("If effort.pressure is medium, choose a narrow next action", prompt)
        self.assertIn("working_memory.target_paths", prompt)
        self.assertIn("prefer a direct read_file on one of those target_paths before repeating same-surface search_text", prompt)
        self.assertIn("prefer those paths before a broader project search", prompt)
        self.assertIn("work_session.world_state.files marks a target_path as exists=false", prompt)
        self.assertIn("do not read_file that missing path", prompt)
        self.assertIn("write_file with create=true", prompt)
        self.assertIn("work_session.resume.target_path_cached_window_observations", prompt)
        self.assertIn("prefer refreshing that direct cached window before repeating same-surface search_text", prompt)
        self.assertIn("reduce first-edit-latency", prompt)
        self.assertIn("same-surface rediscovery", prompt)
        self.assertIn("first-edit old text", prompt)
        self.assertIn("Drop a working_memory.target_paths entry once it is no longer needed for the next step", prompt)
        self.assertIn("do not rerun that same search_text", prompt)
        self.assertIn("switch to a narrow read_file on the anchored window instead", prompt)
        self.assertIn("work_session.resume.search_anchor_observations", prompt)
        self.assertIn("use its suggested_next read_file before repeating that same search_text", prompt)
        self.assertIn("work_session.resume.low_yield_observations", prompt)
        self.assertIn("do not keep searching that same path/pattern", prompt)
        self.assertIn("work_session.resume.redundant_search_observations", prompt)
        self.assertIn("use its suggested_next read_file replacement instead of rerunning search_text again", prompt)
        self.assertIn("work_session.resume.adjacent_read_observations", prompt)
        self.assertIn("use its suggested_next merged read instead of inching through more small reads", prompt)
        self.assertIn("work_session.resume.repair_anchor_observations", prompt)
        self.assertIn("failed batch or repair loop", prompt)
        self.assertIn("Use work_session.resume.continuity as the reentry contract", prompt)
        self.assertIn("treat continuity.recommendation as the first repair queue", prompt)
        self.assertIn("missing memory, risk, next-action, approval, recovery, verifier, budget, decision, or user-pivot state", prompt)
        self.assertIn("prefer search_text for symbols or option names before broad read_file", prompt)
        self.assertIn("line_start and line_count", prompt)
        self.assertIn("Explicit line_start/line_count reads auto-scale max_chars for edit preparation", prompt)
        self.assertIn("search the broader project tree or allowed read root", prompt)
        self.assertIn("instead of repeating same-file searches", prompt)
        self.assertIn("refresh that same targeted window instead of falling back to an offset read_file from the top of the file", prompt)
        self.assertIn("prefer one batch action", prompt)
        self.assertIn("exact old and new strings", prompt)
        self.assertIn("do not reread the full file solely to prepare edit_file", prompt)
        self.assertIn("include a paired tests/ change", prompt)
        self.assertIn("paired-write constraint applies to code write batches", prompt)
        self.assertIn("Use at most one write/edit per file path in the batch", prompt)
        self.assertIn("prefer one edit_file_hunks action for that path", prompt)
