    def test_search_text_splits_space_separated_include_patterns(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "src").mkdir()
            (root / "tests").mkdir()
            (root / "docs").mkdir()
            (root / "src" / "app.py").write_text("needle in source\n", encoding="utf-8")
            (root / "tests" / "test_app.py").write_text("needle in tests\n", encoding="utf-8")
            (root / "docs" / "note.md").write_text("needle in docs\n", encoding="utf-8")
            (root / "outside.txt").write_text("needle outside\n", encoding="utf-8")

            result = search_text(
                "needle",
                str(root),
                [str(root)],
                max_matches=10,
                context_lines=0,
                pattern="src/** tests/** docs/**",
            )

            matches = "\n".join(result["matches"])
            self.assertIn("src/**", result["patterns"])
            self.assertIn("**/src/**", result["patterns"])
            self.assertIn("tests/**", result["patterns"])
            self.assertIn("**/tests/**", result["patterns"])
            self.assertIn("docs/**", result["patterns"])
            self.assertIn("**/docs/**", result["patterns"])
            self.assertIn("src/app.py", matches)
            self.assertIn("tests/test_app.py", matches)
            self.assertIn("docs/note.md", matches)
            self.assertNotIn("outside.txt", matches)

    def test_search_text_falls_back_when_rg_is_missing(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "src").mkdir()
            (root / ".mew").mkdir()
            (root / "src" / "app.py").write_text("before\nneedle here\nafter\n", encoding="utf-8")
            (root / ".mew" / "state.json").write_text("needle hidden\n", encoding="utf-8")

            with patch("mew.read_tools.subprocess.run", side_effect=FileNotFoundError()):
                result = search_text(
                    "needle",
                    str(root),
                    [str(root)],
                    max_matches=5,
                    context_lines=1,
                    pattern="src/**",
                )

            self.assertEqual(result["engine"], "python")
            self.assertEqual(len(result["matches"]), 1)
            self.assertIn("src/app.py", result["matches"][0])
            self.assertNotIn(".mew", "\n".join(result["matches"]))
            self.assertEqual(result["snippets"][0]["start_line"], 1)
            self.assertEqual(result["snippets"][0]["end_line"], 3)

    def test_search_text_python_fallback_skips_symlink_targets(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            outside = Path(tmp) / "outside"
            root.mkdir()
            outside.mkdir()
            (root / "visible.txt").write_text("ordinary text\n", encoding="utf-8")
            secret = outside / "secret.txt"
            secret.write_text("needle outside root\n", encoding="utf-8")
            try:
                (root / "linked-secret.txt").symlink_to(secret)
            except OSError as exc:
                self.skipTest(f"symlink creation unavailable: {exc}")

            with patch("mew.read_tools.subprocess.run", side_effect=FileNotFoundError()):
                result = search_text(
                    "needle",
                    str(root),
                    [str(root)],
                    max_matches=5,
                    context_lines=0,
                    pattern="*.txt",
                )

            self.assertEqual(result["engine"], "python")
            self.assertEqual(result["matches"], [])
            self.assertGreaterEqual(result["skipped_sensitive"], 1)

    def test_work_model_rejects_resident_loop_as_verification_command(self):
        from mew.work_loop import normalize_work_model_action

        for command in (
            "mew do 1 --read-only",
            "./mew chat",
            "python -m mew run",
            "uv run mew work 1 --live",
            "PYTHONPATH=. ./mew work 1 --live",
            "env -i ./mew work 1 --live",
            "FOO=1 uv run mew work 1 --live",
            "python3 -I -m mew work 1 --live",
        ):
            action = normalize_work_model_action(
                {"summary": "verify", "action": {"type": "run_tests", "command": command}}
            )
            self.assertEqual(action["type"], "wait", command)
            self.assertIn("resident mew loop", action["reason"])

        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests", "command": "uv run pytest -q"}}
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], "uv run pytest -q")

    def test_work_model_uses_suggested_verify_command_when_configured_verifier_missing(self):
        from mew.work_loop import normalize_work_model_action

        suggested = "uv run python -m unittest tests.test_commands"
        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests"}},
            verify_command="",
            suggested_verify_command=suggested,
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], suggested)

        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests"}},
            verify_command="uv run pytest -q",
            suggested_verify_command=suggested,
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], "uv run pytest -q")

