    def test_work_reply_schema_uses_active_session(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--reply-schema", "--json"]), 0)

                data = json.loads(stdout.getvalue())
                session = load_state()["work_sessions"][0]
                self.assertEqual(data["schema_version"], 1)
                self.assertTrue(data["docs_path"].endswith("docs/FOLLOW_REPLY_SCHEMA.md"))
                self.assertEqual(data["session_id"], 1)
                self.assertEqual(data["task_id"], 1)
                self.assertEqual(data["observed_session_updated_at"], session["updated_at"])
                self.assertTrue(data["submit_ready"])
                self.assertFalse(data["schema_only"])
                self.assertEqual(data["reply_command"], "mew work 1 --reply-file .mew/follow/reply.json")
                self.assertEqual(data["reply_template"]["observed_session_updated_at"], session["updated_at"])
                self.assertTrue(any(action["type"] == "reject" for action in data["supported_actions"]))
                self.assertTrue(any(action["type"] == "approve" for action in data["supported_actions"]))
                self.assertTrue(any(action["type"] == "approve_all" for action in data["supported_actions"]))
                self.assertTrue(any(action["type"] == "followup" for action in data["supported_actions"]))
                self.assertTrue(any(action["type"] == "interrupt_submit" for action in data["supported_actions"]))
                approve_action = next(action for action in data["supported_actions"] if action["type"] == "approve")
                self.assertIn("defer_verify", approve_action["optional"])
            finally:
                os.chdir(old_cwd)

