    def test_work_follow_status_reports_fresh_snapshot_when_producer_alive(self):
        from mew.timeutil import now_iso

        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                follow_dir = Path(".mew/follow")
                follow_dir.mkdir(parents=True)
                (follow_dir / "latest.json").write_text(
                    json.dumps(
                        {
                            "schema_version": 1,
                            "mode": "follow",
                            "session_id": 1,
                            "task_id": 1,
                            "heartbeat_at": now_iso(),
                            "producer": {"pid": os.getpid()},
                            "stop_reason": "snapshot_refresh",
                            "step_count": 7,
                            "pending_approvals": [{"tool_call_id": 3}],
                            "resume": {
                                "phase": "idle",
                                "next_action": "Inspect latest snapshot.",
                                "working_memory": {
                                    "next_step": "Refresh from source.",
                                    "stale_after_tool_call_id": 9,
                                },
                                "verification_coverage_warning": {
                                    "command": "uv run python -m unittest tests.test_work_session",
                                    "source_path": "src/mew/commands.py",
                                    "expected_command": "uv run python -m unittest tests.test_commands",
                                },
                                "verification_confidence": {
                                    "status": "partial",
                                    "confidence": "medium",
                                    "reason": "latest verifier passed, but does not appear to cover every inferred paired test",
                                    "expected_command": "uv run python -m unittest tests.test_commands",
                                }
                            },
                        }
                    ),
                    encoding="utf-8",
                )

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "--follow-status", "--json"]), 0)
                data = json.loads(stdout.getvalue())
                self.assertEqual(data["status"], "fresh")
                self.assertTrue(data["producer_alive"])
                self.assertEqual(data["producer_health"]["state"], "fresh")
                self.assertEqual(data["suggested_recovery"], {})
                self.assertEqual(data["pending_approval_count"], 1)
                self.assertEqual(data["step_count"], 7)
                self.assertEqual(data["phase"], "idle")
                self.assertEqual(data["next_action"], "Inspect latest snapshot.")
                self.assertTrue(data["working_memory_stale"])
                self.assertEqual(
                    data["verification_coverage_warning"]["expected_command"],
                    "uv run python -m unittest tests.test_commands",
                )
                self.assertEqual(data["verification_confidence"]["status"], "partial")
                self.assertIsInstance(data["heartbeat_age_seconds"], float)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "--follow-status"]), 0)
                text = stdout.getvalue()
                self.assertIn("phase: idle", text)
                self.assertIn("steps: 7", text)
                self.assertIn("stop_reason: snapshot_refresh", text)
                self.assertIn("producer_health: fresh", text)
                self.assertIn("working_memory: stale", text)
                self.assertIn("next_action: Inspect latest snapshot.", text)
                self.assertIn("verification_warning:", text)
                self.assertIn("did not cover src/mew/commands.py", text)
                self.assertIn("expected uv run python -m unittest tests.test_commands", text)
                self.assertIn("verification_confidence: medium status=partial", text)
            finally:
                os.chdir(old_cwd)

