    def test_work_reply_file_rejects_stale_session_snapshot(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)
                observed_updated_at = load_state()["work_sessions"][0]["updated_at"]
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--session-note", "newer local change"]), 0)
                with state_lock():
                    state = load_state()
                    state["work_sessions"][0]["updated_at"] = "newer-than-observed"
                    save_state(state)
                Path("reply.json").write_text(
                    json.dumps(
                        {
                            "schema_version": 1,
                            "session_id": 1,
                            "task_id": 1,
                            "observed_session_updated_at": observed_updated_at,
                            "actions": [{"type": "steer", "text": "stale guidance"}],
                        }
                    ),
                    encoding="utf-8",
                )

                with redirect_stderr(StringIO()) as stderr:
                    self.assertEqual(main(["work", "--reply-file", "reply.json"]), 1)
                self.assertIn("stale work-session snapshot", stderr.getvalue())
                self.assertNotIn("pending_steer", load_state()["work_sessions"][0])
            finally:
                os.chdir(old_cwd)

    def test_work_reply_file_reject_action_is_single_use(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                target = Path("notes.md")
                target.write_text("before\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)
                with redirect_stdout(StringIO()):
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "notes.md",
                                "--old",
                                "before",
                                "--new",
                                "after",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )
                observed_updated_at = load_state()["work_sessions"][0]["updated_at"]
                Path("reply.json").write_text(
                    json.dumps(
                        {
                            "schema_version": 1,
                            "session_id": 1,
                            "task_id": 1,
                            "observed_session_updated_at": observed_updated_at,
                            "actions": [{"type": "reject", "tool_call_id": 1, "reason": "not wanted"}],
                        }
                    ),
                    encoding="utf-8",
                )

                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "--reply-file", "reply.json"]), 0)
                self.assertEqual(load_state()["work_sessions"][0]["tool_calls"][0]["approval_status"], "rejected")

                with redirect_stderr(StringIO()) as stderr:
                    self.assertEqual(main(["work", "--reply-file", "reply.json"]), 1)
                error = stderr.getvalue()
                self.assertTrue("already rejected" in error or "stale work-session snapshot" in error)
            finally:
                os.chdir(old_cwd)

    def test_chat_work_session_can_approve_and_reject_tool_changes(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.commands import run_chat_slash_command

                target = Path("notes.md")
                target.write_text("before\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "notes.md",
                                "--old",
                                "before",
                                "--new",
                                "after",
                                "--allow-write",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )
                dry_run = json.loads(stdout.getvalue())
                self.assertEqual(dry_run["tool_call"]["id"], 1)
                self.assertEqual(target.read_text(encoding="utf-8"), "before\n")

                command = f"{sys.executable} -c \"from pathlib import Path; assert Path('notes.md').read_text() == 'after\\n'\""
                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        run_chat_slash_command(
                            f"/work-session approve 1 --allow-write . --verify-command {shlex.quote(command)}",
                            {},
                        ),
                        "continue",
                    )
                self.assertIn("approved work tool #1 -> #2 [completed]", stdout.getvalue())
                self.assertEqual(target.read_text(encoding="utf-8"), "after\n")

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "notes.md",
                                "--old",
                                "after",
                                "--new",
                                "never",
                                "--allow-write",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )
                second_dry_run = json.loads(stdout.getvalue())
                self.assertEqual(second_dry_run["tool_call"]["id"], 3)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        run_chat_slash_command("/work-session reject 3 not needed", {}),
                        "continue",
                    )
                self.assertIn("rejected work tool #3", stdout.getvalue())
                state = load_state()
                rejected = state["work_sessions"][0]["tool_calls"][2]
                self.assertEqual(rejected["approval_status"], "rejected")
                self.assertEqual(rejected["rejection_reason"], "not needed")
                self.assertEqual(target.read_text(encoding="utf-8"), "after\n")
            finally:
                os.chdir(old_cwd)

    def test_chat_work_session_approve_can_defer_verification(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.commands import run_chat_slash_command

                target = Path("notes.md")
                target.write_text("before\n", encoding="utf-8")
                command = f"{sys.executable} -c \"raise SystemExit(23)\""
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--start-session",
                                "--allow-write",
                                ".",
                                "--allow-verify",
                                "--verify-command",
                                command,
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "notes.md",
                                "--old",
                                "before",
                                "--new",
                                "after",
                                "--allow-write",
                                ".",
                                "--json",
                            ]
                        ),
                        0,
                    )

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        run_chat_slash_command("/work-session approve 1 --allow-write . --defer-verify", {}),
                        "continue",
                    )

                self.assertIn("approved work tool #1 -> #2 [completed]", stdout.getvalue())
                self.assertEqual(target.read_text(encoding="utf-8"), "after\n")
                applied = load_state()["work_sessions"][0]["tool_calls"][1]
                self.assertTrue(applied["parameters"]["defer_verify"])
                self.assertTrue(applied["result"]["verification_deferred"])
                self.assertNotIn("verification_exit_code", applied["result"])
            finally:
                os.chdir(old_cwd)

    def test_chat_work_session_can_approve_all_tool_changes(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.commands import run_chat_slash_command

                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "write_file",
                                "--path",
                                "one.md",
                                "--content",
                                "one\n",
                                "--create",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "write_file",
                                "--path",
                                "two.md",
                                "--content",
                                "two\n",
                                "--create",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        run_chat_slash_command(
                            "/work-session approve all --allow-write . --verify-command true",
                            {},
                        ),
                        "continue",
                    )

                output = stdout.getvalue()
                self.assertIn("approved work tool #1", output)
                self.assertIn("approved work tool #2", output)
                self.assertEqual(Path("one.md").read_text(encoding="utf-8"), "one\n")
                self.assertEqual(Path("two.md").read_text(encoding="utf-8"), "two\n")
            finally:
                os.chdir(old_cwd)
